 67 /// Given an icmp instruction, return true if any use of this comparison is a
 68 /// branch on sign bit comparison.
 69 static bool hasBranchUse(ICmpInst &I) {
 70   for (auto *U : I.users())
 71     if (isa<BranchInst>(U))
 72       return true;
 73   return false;
 74 }
