933                                                   CmpPredicate Pred) {
934   // From this point on, we know that (X+C <= X) --> (X+C < X) because C != 0,
935   // so the values can never be equal.  Similarly for all other "or equals"
936   // operators.
937   assert(!!C && "C should not be zero!");
